const preco = 49.9;
const desconto = 0.1;

function App() {
  return (
    <div>
      <p>Preço original: R$ {preco.toFixed(2)}</p>
      <p>Desconto: {desconto * 100}%</p>
      <p>Preço final: R$ {(preco * (1 - desconto)).toFixed(2)}</p>
      <p>Status: {preco > 40 ? 'Premium' : 'Básico'}</p>
    </div>
  );
}

// ❌ Isso NÃO funciona:
// {if (logado) { return <p>Olá</p> }}

// ✅ Use ternário:
{logado ? <p>Olá!</p> : <p>Faça login</p>}

// ✅ Use && para renderizar condicionalmente:
{logado && <p>Bem-vindo de volta!</p>}

